#include <stdio.h>
#include <math.h>

int main(void) {
    double temp;
    char scale;
    double converted;

    scanf("%lf %c", &temp, &scale);

    if (scale == 'C') {
        converted = temp * 9.0 / 5.0 + 32.0;
        if (converted < -459.67) {
            printf("Error: Temperature below absolute zero\n");
        } else {
            printf("%.1f\n", converted);
        }
    } else if (scale == 'F') {
        converted = (temp - 32.0) * 5.0 / 9.0;
        if (converted < -273.15) {
            printf("Error: Temperature below absolute zero\n");
        } else {
            printf("%.1f\n", converted);
        }
    }

    return 0;
}

#include <stdio.h>

int main(void) {
    int num;
    int sum = 0;
    int digit;

    scanf("%d", &num);

    while (num > 0) {
        digit = num % 10;
        sum = sum + digit;
        num = num / 10;
    }

    printf("%d\n", sum);

    return 0;
}

#include <stdio.h>

int main(void) {
    int num;
    int even_count = 0;
    int odd_count = 0;

    while (scanf("%d", &num) == 1) {
        if (num % 2 == 0) {
            even_count = even_count + 1;
        } else {
            odd_count = odd_count + 1;
        }
    }

    printf("%d\n", even_count);
    printf("%d\n", odd_count);

    return 0;
}

#include <stdio.h>

int main(void) {
    int n, t;

    scanf("%d %d", &n, &t);

    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n; j++) {
            int product = i * j;
            if (product < t) {
                printf("[%d]", product);
            } else {
                printf("%d", product);
            }
            if (j < n) {
                printf("\t");
            }
        }
        printf("\n");
    }

    return 0;
}

#include <stdio.h>

int main(void) {
    double num;
    double sum = 0.0;
    int count = 0;

    while (scanf("%lf", &num) == 1) {
        sum = sum + num;
        count = count + 1;
        double average = sum / count;
        printf("%.2f\n", average);
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int prev, curr;

    scanf("%d", &prev);

    while (scanf("%d", &curr) == 1) {
        int diff = abs(prev - curr);
        printf("%d\n", diff);
        prev = curr;
    }

    return 0;
}

#include <stdio.h>

int main(void) {
    int score;

    scanf("%d", &score);

    if (score < 0 || score > 100) {
        printf("Error: Score out of range\n");
    } else if (score >= 90) {
        printf("A\n");
    } else if (score >= 80) {
        printf("B\n");
    } else if (score >= 70) {
        printf("C\n");
    } else if (score >= 60) {
        printf("D\n");
    } else {
        printf("F\n");
    }

    return 0;
}

#include <stdio.h>

int main(void) {
    int a, b;

    scanf("%d %d", &a, &b);

    int a_copy = a;
    int b_copy = b;

    while (b_copy != 0) {
        int temp = b_copy;
        b_copy = a_copy % b_copy;
        a_copy = temp;
    }

    int gcd = a_copy;
    int lcm = (a / gcd) * b;

    printf("%d\n", lcm);

    return 0;
}

#include <stdio.h>

int main(void) {
    int amount;

    scanf("%d", &amount);

    int quarters = amount / 25;
    amount = amount % 25;

    int dimes = amount / 10;
    amount = amount % 10;

    int nickels = amount / 5;
    amount = amount % 5;

    int pennies = amount;

    printf("%d\n", quarters);
    printf("%d\n", dimes);
    printf("%d\n", nickels);
    printf("%d\n", pennies);

    return 0;
}

#include <stdio.h>
#include <math.h>

int main(void) {
    long long base, exponent, modulus;

    scanf("%lld %lld %lld", &base, &exponent, &modulus);

    long long result = 1;
    for (long long i = 0; i < exponent; i++) {
        result = result * base;
    }

    long long remainder = result % modulus;

    printf("%lld\n", result);
    printf("%lld\n", remainder);

    return 0;
}
